import logging

import grpc
from envoy_auth_ext_authz_grpc.v3 import CheckRequest, CheckResponse
from envoy_auth_ext_authz_grpc.v3 import ExtAuthzServiceServicer, ExtAuthzServiceServer
from envoy_auth_ext_authz_grpc.v3 import Status

class CustomAuthzService(ExtAuthzServiceServicer):

    def Check(self, request: CheckRequest, context: grpc.ServicerContext) -> CheckResponse:
        # Get custom headers from the request
        custom_header_value = context.request().headers.get('custom_header')

        # Perform authorization logic based on custom header value
        if custom_header_value == 'authorized':
            return CheckResponse(status=Status.OK)
        else:
            return CheckResponse(status=Status.PERMISSION_DENIED)

